-- ----------------------------------------------------------------------------
-- vw_dev_users: Table: DevUsers
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_dev_users WITH (security_invoker = ON) AS
SELECT
  t.dev_users_id,                                                               -- Primary key (auto-synthesized: DevUsers had no field named 'Id' or ending in 'Id').
  t.email,                                                                      -- User email (also PK)
  calc_dev_users_name(t.dev_users_id) AS name,                                  -- Display name
  t.role                                                                        -- commissioner, owner, or spectator
FROM dev_users t;

-- ----------------------------------------------------------------------------
-- vw_players: Table: Players
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_players WITH (security_invoker = ON) AS
SELECT
  t.player_id,                                                                  -- Player slug (PK)
  calc_players_name(t.player_id) AS name,                                       -- Display name
  t.position,                                                                   -- QB, RB, WR, TE
  t.passing_yards,                                                              -- Season passing yards
  t.passing_touchdowns,                                                         -- Season passing TDs
  t.interceptions,                                                              -- Season INTs
  t.rushing_yards,                                                              -- Season rushing yards
  t.rushing_touchdowns,                                                         -- Season rushing TDs
  t.receptions,                                                                 -- Season receptions
  t.received_yards,                                                             -- Season receiving yards
  t.received_touchdowns,                                                        -- Season receiving TDs
  calc_players_total_touchdowns(t.player_id) AS total_touchdowns,               -- Sum of all TDs
  calc_players_projected_score(t.player_id) AS projected_score                  -- Calculated fantasy points
FROM players t;

-- ----------------------------------------------------------------------------
-- vw_rosters: Table: Rosters
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_rosters WITH (security_invoker = ON) AS
SELECT
  t.roster_id,                                                                  -- Team slug (PK)
  calc_rosters_name(t.roster_id) AS name,                                       -- Display name
  t.owner,                                                                      -- Owner email
  calc_rosters_total_passing_yards(t.roster_id) AS total_passing_yards,         -- Sum of QB passing yards on roster
  calc_rosters_total_rushing_yards(t.roster_id) AS total_rushing_yards,         -- Sum of rushing yards on roster
  calc_rosters_total_receiving_yards(t.roster_id) AS total_receiving_yards,     -- Sum of receiving yards on roster
  calc_rosters_total_touchdowns(t.roster_id) AS total_touchdowns,               -- Sum of all TDs on roster
  calc_rosters_total_interceptions(t.roster_id) AS total_interceptions,         -- Sum of INTs on roster
  calc_rosters_projected_score(t.roster_id) AS projected_score                  -- Total roster fantasy points (2nd-order calc)
FROM rosters t;

-- ----------------------------------------------------------------------------
-- vw_roster_assignments: Table: RosterAssignments (join table linking Players to Rosters)
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_roster_assignments WITH (security_invoker = ON) AS
SELECT
  t.assignment_id,                                                              -- Unique assignment ID (PK)
  calc_roster_assignments_name(t.assignment_id) AS name,                        -- Display name
  t.roster,                                                                     -- Roster FK
  t.player,                                                                     -- Player FK
  calc_roster_assignments_player_name(t.assignment_id) AS player_name,          -- Player display name
  calc_roster_assignments_position(t.assignment_id) AS position,                -- Player position
  calc_roster_assignments_passing_yards(t.assignment_id) AS passing_yards,      -- Player passing yards
  calc_roster_assignments_passing_touchdowns(t.assignment_id) AS passing_touchdowns,-- Player passing TDs
  calc_roster_assignments_interceptions(t.assignment_id) AS interceptions,      -- Player INTs
  calc_roster_assignments_rushing_yards(t.assignment_id) AS rushing_yards,      -- Player rushing yards
  calc_roster_assignments_rushing_touchdowns(t.assignment_id) AS rushing_touchdowns,-- Player rushing TDs
  calc_roster_assignments_receptions(t.assignment_id) AS receptions,            -- Player receptions
  calc_roster_assignments_received_yards(t.assignment_id) AS received_yards,    -- Player receiving yards
  calc_roster_assignments_received_touchdowns(t.assignment_id) AS received_touchdowns,-- Player receiving TDs
  calc_roster_assignments_total_touchdowns(t.assignment_id) AS total_touchdowns,-- Player total TDs
  calc_roster_assignments_projected_score(t.assignment_id) AS projected_score   -- Player projected score
FROM roster_assignments t;

-- ----------------------------------------------------------------------------
-- vw_matchups: Table: Matchups
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_matchups WITH (security_invoker = ON) AS
SELECT
  t.matchup_id,                                                                 -- Unique matchup ID (PK)
  calc_matchups_name(t.matchup_id) AS name,                                     -- Display name
  t.week,                                                                       -- Week number
  t.team1,                                                                      -- First roster
  t.team2,                                                                      -- Second roster
  calc_matchups_team1_score(t.matchup_id) AS team1_score,                       -- Team1's projected score
  calc_matchups_team2_score(t.matchup_id) AS team2_score,                       -- Team2's projected score
  calc_matchups_margin(t.matchup_id) AS margin,                                 -- Team1 score minus Team2 score
  calc_matchups_winner(t.matchup_id) AS winner,                                 -- Winning roster ID
  calc_matchups_loser(t.matchup_id) AS loser,                                   -- Losing roster ID
  calc_matchups_is_tie_game(t.matchup_id) AS is_tie_game                        -- True if scores are equal
FROM matchups t;

-- ----------------------------------------------------------------------------
-- vw_standings: Table: Standings
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_standings WITH (security_invoker = ON) AS
SELECT
  t.standing_id,                                                                -- Roster ID used as standing ID (PK)
  calc_standings_name(t.standing_id) AS name,                                   -- Roster name
  calc_standings_owner(t.standing_id) AS owner,                                 -- Owner email
  t.wins,                                                                       -- Count of matchups won
  t.losses,                                                                     -- Count of matchups lost
  t.ties,                                                                       -- Count of tied matchups
  t.win_pct,                                                                    -- Win percentage
  t.points_for,                                                                 -- Total points scored by this roster
  t.points_against,                                                             -- Total points allowed
  t.seed_rank,                                                                  -- Playoff seed (manually set)
  t.playoff_bound,                                                              -- True if seeded 1-6
  t.champs_path                                                                 -- If playoff-bound, path to championship
FROM standings t;

